import {
  ADMIN_DB_COOKIE,
  adminCookieOptions,
  signAdminToken,
  verifyAdminToken,
} from '@/lib/admin-auth';
import { cookies } from 'next/headers';
import { NextResponse } from 'next/server';

export async function POST(req: Request) {
  const { password } = (await req.json()) as { password?: string };
  const expected = process.env.ADMIN_DB_PASSWORD;

  if (!expected) {
    return NextResponse.json(
      { error: 'Server not configured' },
      { status: 500 }
    );
  }

  if (!password || password !== expected) {
    return NextResponse.json({ error: 'Invalid password' }, { status: 401 });
  }

  const token = await signAdminToken();
  const cookieStore = await cookies();
  cookieStore.set(ADMIN_DB_COOKIE, token, adminCookieOptions());

  return NextResponse.json({ success: true });
}

export async function DELETE() {
  const cookieStore = await cookies();
  cookieStore.delete(ADMIN_DB_COOKIE);
  return NextResponse.json({ success: true });
}

export async function GET() {
  const cookieStore = await cookies();
  const token = cookieStore.get(ADMIN_DB_COOKIE)?.value;

  if (!token) {
    return NextResponse.json({ authenticated: false });
  }

  const payload = await verifyAdminToken(token);
  return NextResponse.json({ authenticated: payload !== null });
}

import { getDb } from '@/db';
import { ADMIN_DB_COOKIE, verifyAdminToken } from '@/lib/admin-auth';
import { sql } from 'drizzle-orm';
import { cookies } from 'next/headers';
import { NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

export async function GET() {
  const cookieStore = await cookies();
  const token = cookieStore.get(ADMIN_DB_COOKIE)?.value;
  if (!token || !(await verifyAdminToken(token))) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const db = await getDb();

  const tables = await db.execute<{
    table_name: string;
    row_estimate: string;
  }>(sql`
    SELECT
      t.table_name,
      COALESCE(
        (SELECT reltuples::bigint FROM pg_class WHERE relname = t.table_name),
        0
      ) AS row_estimate
    FROM information_schema.tables t
    WHERE t.table_schema = 'public'
      AND t.table_type = 'BASE TABLE'
    ORDER BY t.table_name
  `);

  return NextResponse.json({
    tables: tables.rows.map((t) => ({
      name: t.table_name,
      rowEstimate: Number(t.row_estimate),
    })),
  });
}

import { getDb } from '@/db';
import { ADMIN_DB_COOKIE, verifyAdminToken } from '@/lib/admin-auth';
import { sql } from 'drizzle-orm';
import { cookies } from 'next/headers';
import { type NextRequest, NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

async function validateTableName(db: Awaited<ReturnType<typeof getDb>>, name: string) {
  const result = await db.execute<{ table_name: string }>(sql`
    SELECT table_name FROM information_schema.tables
    WHERE table_schema = 'public'
      AND table_type = 'BASE TABLE'
      AND table_name = ${name}
  `);
  return result.rows.length > 0;
}

export async function GET(
  req: NextRequest,
  { params }: { params: Promise<{ table: string }> }
) {
  const cookieStore = await cookies();
  const token = cookieStore.get(ADMIN_DB_COOKIE)?.value;
  if (!token || !(await verifyAdminToken(token))) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const { table } = await params;
  const db = await getDb();

  const valid = await validateTableName(db, table);
  if (!valid) {
    return NextResponse.json({ error: 'Table not found' }, { status: 404 });
  }

  const searchParams = req.nextUrl.searchParams;
  const page = Math.max(1, Number(searchParams.get('page') ?? '1'));
  const pageSize = Math.min(
    100,
    Math.max(1, Number(searchParams.get('pageSize') ?? '20'))
  );
  const sortCol = searchParams.get('sort');
  const sortOrder = searchParams.get('order') === 'desc' ? 'DESC' : 'ASC';
  const offset = (page - 1) * pageSize;

  const columns = await db.execute<{
    column_name: string;
    data_type: string;
    is_nullable: string;
    column_default: string | null;
  }>(sql`
    SELECT column_name, data_type, is_nullable, column_default
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = ${table}
    ORDER BY ordinal_position
  `);

  const columnNames = columns.rows.map((c) => c.column_name);

  let orderClause = sql`1`;
  if (sortCol && columnNames.includes(sortCol)) {
    orderClause =
      sortOrder === 'DESC'
        ? sql`${sql.identifier(sortCol)} DESC`
        : sql`${sql.identifier(sortCol)} ASC`;
  }

  const [rows, countResult] = await Promise.all([
    db.execute(
      sql`SELECT * FROM ${sql.identifier(table)} ORDER BY ${orderClause} LIMIT ${pageSize} OFFSET ${offset}`
    ),
    db.execute<{ count: string }>(
      sql`SELECT count(*)::text AS count FROM ${sql.identifier(table)}`
    ),
  ]);

  const total = Number(countResult.rows[0]?.count ?? 0);

  return NextResponse.json({
    columns: columns.rows.map((c) => ({
      name: c.column_name,
      type: c.data_type,
      nullable: c.is_nullable === 'YES',
      default: c.column_default,
    })),
    rows: rows.rows,
    total,
    page,
    pageSize,
  });
}

'use client';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Database, Loader2 } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useState } from 'react';

export default function AdminLoginPage() {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const res = await fetch('/api/admin/auth', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ password }),
      });

      if (!res.ok) {
        setError('密码错误');
        return;
      }

      router.push('/admin/database');
    } catch {
      setError('请求失败，请重试');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="flex min-h-screen items-center justify-center p-4">
      <Card className="w-full max-w-sm">
        <CardHeader className="text-center">
          <div className="mx-auto mb-2 flex size-12 items-center justify-center rounded-full bg-muted">
            <Database className="size-6 text-muted-foreground" />
          </div>
          <CardTitle className="text-xl">Database Admin</CardTitle>
          <p className="text-sm text-muted-foreground">
            输入密码以访问数据库管理面板
          </p>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Input
                type="password"
                placeholder="请输入管理密码"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                autoFocus
                disabled={loading}
              />
              {error && (
                <p className="text-sm text-destructive">{error}</p>
              )}
            </div>
            <Button type="submit" className="w-full" disabled={loading}>
              {loading && <Loader2 className="mr-2 size-4 animate-spin" />}
              进入
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

